svg.script:
(function() {
  var svg = document.querySelector('svg');
  var grad = document.getElementById('shimmer-gradient');
  var overlay = document.getElementById('shimmer-overlay');
  var hueMatrix = document.getElementById('shimmer-hue');
  var currentOpacity = 0;
  var targetOpacity = 0;
  var currentCx = 540, currentCy = 960;
  var targetCx = 540, targetCy = 960;

  function getSVGPoint(e) {
    var pt = svg.createSVGPoint();
    pt.x = e.clientX;
    pt.y = e.clientY;
    return pt.matrixTransform(svg.getScreenCTM().inverse());
  }

  svg.addEventListener('mousemove', function(e) {
    var p = getSVGPoint(e);
    targetCx = p.x;
    targetCy = p.y;
    targetOpacity = 0.6;
    var angle = Math.atan2(p.y - 960, p.x - 540) * (180 / Math.PI);
    hueMatrix.setAttribute('values', (((angle + 360) % 360) * 0.3).toFixed(1));
  });

  svg.addEventListener('mouseleave', function() {
    targetOpacity = 0;
  });

  function animate() {
    currentCx += (targetCx - currentCx) * 0.04;
    currentCy += (targetCy - currentCy) * 0.04;
    currentOpacity += (targetOpacity - currentOpacity) * 0.03;
    grad.setAttribute('cx', currentCx.toFixed(1));
    grad.setAttribute('cy', currentCy.toFixed(1));
    grad.setAttribute('fx', currentCx.toFixed(1));
    grad.setAttribute('fy', currentCy.toFixed(1));
    overlay.setAttribute('opacity', currentOpacity.toFixed(3));
    requestAnimationFrame(animate);
  }
  animate();
})();
